mapper.update:
WITH UPSERT AS (
    UPDATE NIA.TB_EQUIP_MST
       SET SYSNAME = #{sysname}
         , PSU = #{psu}
         , MODEL = #{model}
         , SID = #{sid}
         , SW_VER = #{swVer}
         , SW_CHKSUM = #{swChksum}
         , SW_DATE = #{swDate}
         , SW_TIME = #{swTime}
     WHERE TID = #{tid}
    RETURNING *
)
INSERT INTO NIA.TB_EQUIP_MST
(
    TID, SYSNAME, PSU, MODEL, SID, SW_VER, SW_CHKSUM, SW_DATE, SW_TIME
)
SELECT #{tid}, #{sysname}, #{psu}, #{model}, #{sid}, #{swVer}, #{swChksum}, #{swDate}, #{swTime}
 WHERE NOT EXISTS (SELECT * FROM UPSERT)
